"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[889],{4774:(e,i,n)=>{n.d(i,{$:()=>c});var t=n(785),r=n(549),a=n(7945),o=n(844),s=n(7653);let l=(0,o.F)("inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0 hover-elevate active-elevate-2",{variants:{variant:{default:"bg-primary text-primary-foreground border border-primary-border",destructive:"bg-destructive text-destructive-foreground shadow-sm border-destructive-border",outline:" border [border-color:var(--button-outline)] shadow-xs active:shadow-none ",secondary:"border bg-secondary text-secondary-foreground border border-secondary-border ",ghost:"border border-transparent",link:"text-primary underline-offset-4 hover:underline"},size:{default:"min-h-9 px-4 py-2",sm:"min-h-8 rounded-md px-3 text-xs",lg:"min-h-10 rounded-md px-8",icon:"h-9 w-9"}},defaultVariants:{variant:"default",size:"default"}}),c=r.forwardRef((e,i)=>{let{className:n,variant:r,size:o,asChild:c=!1,...d}=e,h=c?a.DX:"button";return(0,t.jsx)(h,{className:(0,s.cn)(l({variant:r,size:o,className:n})),ref:i,...d})});c.displayName="Button"},6648:(e,i,n)=>{n.d(i,{$p:()=>f,dC:()=>w,j2:()=>v});var t=n(3037),r=n(4385),a=n(740),o=n(8824),s=n(511),l=n(7032),c=n(6239),d=n(7424),h=n(378),u=n(3941),g=n(7319),p=n(893),m=n(266),y=n(9488);let f=[{slug:"engine-diagnostics",name:"Engine Diagnostics",category:"Auto Services",icon:t.A,image:"/images/services/engine-diagnostics.jpg",shortDescription:"Computerized diagnostics to find the root cause of issues.",seoTitle:"Engine Diagnostics in Springfield, Woodbridge & Northern Virginia, VA",fullDescription:"Advanced computerized diagnostics to find the root cause of warning lights and performance issues. Our technicians use state-of-the-art equipment to accurately identify and resolve engine problems before they become major repairs. When your check engine light comes on, Bingo Tire & Auto Service in Northern Virginia is the trusted name drivers in Springfield, Woodbridge, Alexandria, Centreville, and Winchester rely on.",bodyParagraphs:["Modern vehicles are equipped with sophisticated on-board computers that monitor hundreds of systems and sensors simultaneously. When something goes wrong, a trouble code is stored — but that code is only the starting point, not the diagnosis. At Bingo Tire & Auto Service, our ASE-certified technicians go beyond simply reading codes. We analyze live data streams, test individual sensors and actuators, and use hands-on experience across all makes and models to find the true root cause of your engine problem. This prevents the costly mistake of replacing parts that were never faulty in the first place.","Many vehicle owners in Northern Virginia make the mistake of getting a free code scan at a parts store, only to replace component after component without fixing the real issue. A true engine diagnostic involves understanding which system is affected, isolating the fault, and confirming the repair. Our technicians work on everything from Ford F-150s and Honda Civics to Jeep Grand Cherokees and European imports. Whatever you drive, we have the tools and the experience to diagnose it accurately and get you back on the road."],seoDescription:"Is your check engine light on? Bingo Tire & Auto Service in Northern Virginia uses advanced computerized diagnostics to pinpoint engine problems fast — saving you time and money. Serving Springfield, Woodbridge, Alexandria, Centreville, and Winchester.",cityContent:"Bingo Tire & Auto Service offers professional engine diagnostics at five convenient locations across Northern Virginia — Springfield at 7661 Fullerton Rd, Woodbridge at 1330 Old Bridge Rd, Alexandria at 2920 Richmond Hwy, Centreville at 13600 Lee Hwy, and Winchester at 709 N Loudoun St. Whether your check engine light just came on during your commute in Springfield or you've been ignoring a warning light for weeks in Alexandria, we're here to help. Walk-ins are welcome at all locations, and we'll get your vehicle on the lift and diagnosed as quickly as possible.",whyUs:"Bingo Tire & Auto Service has been diagnosing and repairing vehicles in Northern Virginia since 2004. What sets us apart from dealerships and chain shops is our commitment to honest, straightforward service. We will never recommend a repair you don't need or inflate a problem to pad your bill. When we diagnose your vehicle, you receive a clear, written explanation of what we found — with no pressure to proceed. Our technicians take pride in explaining the issue in plain language so you can make an informed decision. Whether you're a first-time customer from Woodbridge or a longtime regular from Centreville, you'll be treated with the same respect and honesty every time.",warnings:["Check engine light or service engine soon light is on","Reduced fuel economy","Engine misfires or rough idling","Sluggish acceleration or loss of power","Unusual engine smells or increased emissions","Unusual noises from the engine bay"],included:["Full OBD-II diagnostic scan","Retrieval of all stored fault codes","Inspection of sensors, actuators, and wiring","Live data stream analysis","Detailed written report of findings","Repair recommendations and cost estimate"],faqs:[{question:"Can I drive with the check engine light on?",answer:"It depends on the situation. If the light is steady, you can drive cautiously and get it checked soon. If it's flashing, stop driving as soon as it's safe — a flashing check engine light indicates a serious issue like a misfiring engine that can damage your catalytic converter."},{question:"How long does a diagnostic take?",answer:"Most engine diagnostics take between 30 and 60 minutes. Complex issues requiring additional inspection may take longer. We'll give you a clear timeframe when you arrive."},{question:"Will diagnosing the code fix my car?",answer:"Diagnostics identifies the problem — the repair is a separate step. We'll provide a clear written estimate for any needed repairs, and you can decide how to proceed with no pressure."},{question:"How much does an engine diagnostic cost?",answer:"Our diagnostic fee is competitive with other shops in Springfield, Woodbridge, and across Northern Virginia. In many cases, if you have the repair done with us, the diagnostic fee is applied toward the repair cost. Call your nearest location for current pricing."},{question:"My check engine light has been on for a year and my car seems fine — should I still get it checked?",answer:"Yes, absolutely. Some codes relate to non-urgent issues, but others — like a misfiring cylinder — cause ongoing damage even when the car drives normally. An unresolved misfire can destroy a catalytic converter, turning a $200 repair into a $1,500 one. Don't ignore it."}]},{slug:"brake-repair",name:"Brake Repair",category:"Auto Services",icon:r.A,image:"/images/services/brake-repair.jpg",shortDescription:"Full brake inspection, pad replacement, and fluid flush.",seoTitle:"Brake Repair & Service in Springfield, Woodbridge & Northern Virginia, VA",fullDescription:"Full brake inspection, pad replacement, rotor resurfacing or replacement, and brake fluid flush at all five Bingo Tire & Auto Service locations in Northern Virginia. Don't compromise on safety — our comprehensive brake services ensure your vehicle stops reliably every time. We service brake systems on every make and model, from daily commuters to commercial vans.",bodyParagraphs:["Your brakes are the single most important safety system on your vehicle. At Bingo Tire & Auto Service, we take brake service seriously — every inspection is thorough, every recommendation is honest, and every repair is done to factory standards. Brake pad compounds, rotor metallurgy, and caliper designs vary significantly across vehicle manufacturers. That's why our technicians are trained to inspect the entire system, not just the parts that are visually worn. We stock OEM-equivalent pads and rotors for popular vehicles in the NOVA area, including Ford, Chevrolet, Toyota, Honda, Nissan, Hyundai, Jeep, Dodge, and more.","We'll never recommend new parts if existing ones still have safe service life remaining. When you bring your vehicle to any of our Northern Virginia locations for brake service, our technician will measure pad thickness, assess rotor condition, inspect calipers and hardware, and check brake fluid quality. You'll receive an honest assessment and a clear, written estimate before any work begins. Many of our customers from Springfield, Woodbridge, and Alexandria have been trusting us with their brakes for years — because they know we'll never steer them wrong."],seoDescription:"Get professional brake repair in Northern Virginia at Bingo Tire & Auto Service. We offer same-day brake pad replacement, rotor resurfacing, caliper service, and brake fluid flushes at all 5 locations. Trusted since 2004.",cityContent:"Bingo Tire & Auto Service provides professional brake repair and inspection at five Northern Virginia locations: Springfield (703-440-0880), Woodbridge (703-494-8888), Alexandria (703-548-0333), Centreville (703-543-6900), and Winchester (540-667-7777). When your brakes need attention, don't delay — failing brakes are a safety emergency. Come to your nearest Bingo Tire location for same-day brake inspection and repair. Walk-ins are welcome, and we'll work to get you back on the road safely and quickly.",whyUs:"Since 2004, Bingo Tire & Auto Service has built a reputation across Northern Virginia for honest, reliable brake service. We've earned the trust of thousands of customers in Springfield, Woodbridge, Alexandria, Centreville, and Winchester by treating every car like it belongs to a family member. When you bring your vehicle in for brake work, we show you what we found, explain your options in plain language, and let you make the decision — no pressure, no unnecessary upsells. We stand behind every brake repair we perform with our quality guarantee.",warnings:["Squealing, grinding, or screeching when braking","Vehicle pulls to one side when stopping","Brake pedal feels spongy or sinks to the floor","Vibration or shuddering through the steering wheel","Brake warning light illuminated on dashboard","Longer stopping distances than usual"],included:["Complete brake system inspection","Brake pad thickness measurement","Rotor condition assessment (resurfacing or replacement)","Caliper inspection and lubrication","Brake fluid level and condition check","Brake hose and line inspection"],faqs:[{question:"How often should brake pads be replaced?",answer:"Most brake pads last between 30,000 and 70,000 miles depending on your driving habits. City drivers who stop frequently tend to wear pads faster. We recommend an inspection at every tire rotation."},{question:"Do I need to replace rotors when I replace pads?",answer:"Not always. If your rotors are within manufacturer thickness specs and have minimal scoring, they can often be resurfaced. We'll measure them and give you an honest recommendation — we never recommend unnecessary parts."},{question:"How long does brake repair take?",answer:"A standard brake pad and rotor replacement typically takes 1 to 2 hours per axle. We strive for fast turnaround so you can get back on the road the same day."},{question:"Why do my brakes squeak even though the pads are new?",answer:"New brake pads can squeak for the first few hundred miles as they seat against the rotor surface. If squeaking persists beyond 300 miles, it may indicate a glazed rotor, incorrect pad compound, or installation issue. Bring it to any Bingo Tire location in Northern Virginia and we'll check it at no charge."},{question:"Should I be worried about a soft or spongy brake pedal?",answer:"Yes — a spongy pedal usually means air in the brake lines or a failing master cylinder. Both are safety-critical. Do not delay. Visit any of our five Northern Virginia locations immediately for a brake inspection."}]},{slug:"belts-hoses",name:"Belts and Hoses",category:"Auto Services",icon:a.A,image:"/images/services/belts-hoses.jpg",shortDescription:"Inspection and replacement of timing and serpentine belts.",seoTitle:"Belt & Hose Replacement in Springfield, Woodbridge & Northern Virginia, VA",fullDescription:"Inspection and replacement of timing belts, serpentine belts, radiator hoses, and heater hoses at all five Bingo Tire & Auto Service locations in Northern Virginia. Prevent unexpected breakdowns and engine damage with timely replacement of worn belts and hoses before they leave you stranded in Springfield, Woodbridge, or anywhere else in NOVA.",bodyParagraphs:["Belts and hoses are among the most commonly overlooked maintenance items — yet a failed timing belt can destroy an engine in seconds, and a burst coolant hose can leave you stranded on the side of Route 1 or I-95. At Bingo Tire & Auto Service, our technicians inspect every belt and hose during every visit, not just when you ask. We check for cracking, fraying, glazing, tension loss, and soft spots that indicate internal deterioration. Many hoses look fine on the outside but are dangerously compromised internally.","We service belts and hoses on all makes and models common in Northern Virginia, including vehicles from Toyota, Honda, Ford, Chevrolet, Nissan, Hyundai, Subaru, and more. Whether your vehicle has an interference engine that requires precise timing belt replacement intervals or a newer car with a timing chain, we know the service schedule and the right parts for your exact vehicle. We use OEM-equivalent components and manufacturer-specified torque values to ensure your repair lasts."],seoDescription:"Worn belts and hoses are a leading cause of vehicle breakdowns. Bingo Tire & Auto Service in Northern Virginia inspects and replaces timing belts, serpentine belts, and all engine hoses to keep you from getting stranded on the road.",cityContent:"Bingo Tire & Auto Service provides belt and hose inspection, maintenance, and replacement at all five Northern Virginia locations — Springfield, Woodbridge, Alexandria, Centreville, and Winchester. Our shops are conveniently located throughout Fairfax County, Prince William County, and the Shenandoah Valley, making it easy for drivers across the region to get this critical preventive maintenance done without a long drive. Walk-ins are welcome and most belt and hose services can be completed the same day.",whyUs:"Bingo Tire & Auto Service has been keeping Northern Virginia drivers safe since 2004 with preventive maintenance that prevents costly breakdowns. When it comes to belts and hoses, we take a proactive approach — if we see something that looks like it will fail in the next 10,000 miles, we'll tell you now so you can plan ahead, not leave you stranded on Route 50 in Centreville or the Springfield interchange. We'll always explain what we found and why it matters in plain terms, and we'll never replace a part that still has serviceable life remaining.",warnings:["Squealing noise from the engine when starting or accelerating","Cracking, fraying, or glazing visible on belts","Coolant leaks or overheating engine","Air conditioning or power steering stops working","Vehicle doesn't start (timing belt failure)","Battery warning light comes on (serpentine belt failure)"],included:["Visual inspection of all drive belts","Timing belt condition assessment","Serpentine belt tension and condition check","All coolant and heater hose inspection","Belt replacement with OEM or equivalent parts","Hose clamp and fitting inspection"],faqs:[{question:"What happens if my timing belt breaks?",answer:"A broken timing belt can cause catastrophic engine damage in interference engines, potentially bending valves and damaging pistons. Most manufacturers recommend replacement between 60,000 and 100,000 miles — check your owner's manual or ask us."},{question:"How do I know if my serpentine belt needs replacement?",answer:"Look for visible cracking, fraying, or a glazed appearance. You may also hear a high-pitched squeal when the engine starts. Most serpentine belts should be replaced every 60,000 to 100,000 miles."},{question:"Can I replace just one hose?",answer:"You can, but since hoses age together, many shops recommend replacing all hoses when one fails. We'll inspect them all and give you an honest assessment of which need immediate attention."},{question:"Does my car have a timing belt or a timing chain?",answer:"Some engines use a rubber timing belt that requires scheduled replacement; others use a metal timing chain that typically lasts the life of the engine. Bring your vehicle to any Bingo Tire location in Northern Virginia and our technicians will tell you which your vehicle has and what the service interval is."},{question:"How long does a timing belt replacement take?",answer:"Timing belt replacement is a labor-intensive job that typically takes 2 to 5 hours depending on the vehicle. We recommend replacing the water pump and tensioners at the same time, since they are accessed during the same procedure and share a similar service life."}]},{slug:"lube-oil-filters",name:"Lube, Oil & Filters",category:"Auto Services",icon:o.A,image:"/images/services/lube-oil-filters.jpg",shortDescription:"Full-service oil change with multi-point inspection.",seoTitle:"Oil Change Service in Springfield, Woodbridge & Northern Virginia, VA",fullDescription:"Fast, affordable full-service oil changes at all five Bingo Tire & Auto Service locations across Northern Virginia. We offer conventional, synthetic blend, and full synthetic oil changes with a complimentary multi-point inspection included. Walk-ins welcome in Springfield, Woodbridge, Alexandria, Centreville, and Winchester — no appointment needed.",bodyParagraphs:["Engine oil is the lifeblood of your vehicle. It lubricates moving parts, reduces friction, carries heat away from the engine, and suspends contaminants until the next oil change. Over time, oil breaks down thermally, accumulates dirt and combustion byproducts, and loses its ability to protect your engine. At Bingo Tire & Auto Service, we take oil changes seriously — every service includes draining old oil, replacing the filter, refilling with the correct grade and type of oil for your vehicle, and a thorough multi-point inspection of key vehicle systems.","Many drivers in Northern Virginia are unsure whether to use conventional, synthetic blend, or full synthetic oil. Our technicians will recommend the right oil based on your vehicle manufacturer's specifications, your mileage, your driving habits, and the current season. Virginia's hot summers and cold winters both put stress on engine oil — using the right product matters. We stock all major brands and viscosity grades and will use exactly what your owner's manual calls for."],seoDescription:"Fast, affordable oil changes in Northern Virginia at Bingo Tire & Auto Service. We offer conventional, synthetic blend, and full synthetic oil changes with a multi-point inspection included. Walk-ins welcome at all 5 locations.",cityContent:"Need an oil change in Springfield, Woodbridge, Alexandria, Centreville, or Winchester? Bingo Tire & Auto Service has you covered with fast, professional oil change service at all five Northern Virginia locations. Our Springfield shop at 7661 Fullerton Rd, Woodbridge at 1330 Old Bridge Rd, Alexandria at 2920 Richmond Hwy, Centreville at 13600 Lee Hwy, and Winchester at 709 N Loudoun St are all equipped to handle your oil change quickly. No appointment is needed — just pull in and our team will take care of you.",whyUs:"Since 2004, Bingo Tire & Auto Service has been the go-to oil change shop for thousands of drivers in Springfield, Woodbridge, Alexandria, Centreville, and Winchester. What keeps customers coming back isn't just our competitive pricing — it's the fact that we treat every oil change as an opportunity to check your vehicle's overall health. We'll flag anything we notice during the multi-point inspection and let you know, but we'll never pressure you into additional services. Honest, fast, and thorough — that's the Bingo Tire difference.",warnings:["Oil change reminder light is on","Engine oil appears dark or gritty on the dipstick","You've driven over 3,000–5,000 miles since your last oil change","Engine sounds louder or is knocking","Burning oil smell inside or outside the car","Oil level is consistently low between changes"],included:["Drain and replace engine oil (all types available)","New oil filter installation","Tire pressure check and top-off on all four tires","Windshield washer fluid top-off","Visual inspection of belts and hoses","Brake fluid and coolant level check","Complimentary multi-point vehicle inspection"],faqs:[{question:"How often should I change my oil?",answer:"Conventional oil typically needs changing every 3,000 to 5,000 miles. Full synthetic oil can last 7,500 to 10,000 miles or more. Check your owner's manual or ask us — we'll recommend what's right for your specific vehicle and driving conditions."},{question:"What type of oil does my car need?",answer:"The correct oil viscosity and type is listed in your owner's manual. We carry all grades of conventional, synthetic blend, and full synthetic oils and will use exactly what your manufacturer specifies."},{question:"How long does an oil change take?",answer:"Most oil changes take 20 to 30 minutes. With the multi-point inspection included, plan for about 30 to 45 minutes. No appointment needed — walk-ins are welcome at all five of our Northern Virginia locations."},{question:"Can I bring my own oil or filter?",answer:"Yes, we're happy to perform an oil change with oil and a filter you supply. Just make sure you bring the correct viscosity and a filter that fits your vehicle. Our technicians will verify the specs before installation."},{question:"What's included in the multi-point inspection?",answer:"Our complimentary multi-point inspection includes a visual check of your brakes, tires, belts, hoses, fluid levels, battery terminals, lights, and exhaust. If we notice anything that needs attention, we'll let you know — no pressure to act immediately."}]},{slug:"wheel-alignment",name:"Wheel Alignment",category:"Auto Services",icon:s.A,image:"/images/services/wheel-alignment.jpg",shortDescription:"Computer-aided alignment to manufacturer specs.",seoTitle:"Wheel Alignment in Springfield, Woodbridge & Northern Virginia, VA",fullDescription:"Computerized four-wheel alignment to manufacturer specifications at all five Bingo Tire & Auto Service locations in Northern Virginia. Proper alignment prevents premature tire wear, improves fuel efficiency, and ensures your vehicle handles safely and predictably. We align all makes and models in Springfield, Woodbridge, Alexandria, Centreville, and Winchester.",bodyParagraphs:["Every time your vehicle hits a pothole, curb, or rough patch of road — and Northern Virginia roads have plenty of all three — your wheel alignment can shift. Even small alignment deviations compound over time, causing your tires to scrub against the pavement at a slight angle. The result is accelerated tire wear, reduced fuel efficiency, and a vehicle that pulls to one side. At Bingo Tire & Auto Service, our computerized alignment equipment measures toe, camber, and caster angles to fractions of a degree, then adjusts to the exact specifications set by your vehicle's manufacturer.","Proper wheel alignment is one of the most cost-effective ways to protect your tire investment. A set of four tires that should last 50,000 miles can wear out in as little as 20,000 miles if the alignment is significantly off. If you've recently installed new tires, hit a significant pothole on I-395 or Route 7, or if your vehicle has been pulling to one side, it's time for an alignment check at Bingo Tire & Auto Service."],seoDescription:"Poor alignment costs you money in premature tire wear and reduced fuel efficiency. Get computerized wheel alignment at Bingo Tire & Auto Service in Northern Virginia. We align all makes and models to factory specs.",cityContent:"Bingo Tire & Auto Service performs computerized wheel alignment at five Northern Virginia locations: Springfield at 7661 Fullerton Rd, Woodbridge at 1330 Old Bridge Rd, Alexandria at 2920 Richmond Hwy, Centreville at 13600 Lee Hwy, and Winchester at 709 N Loudoun St. Drivers throughout Fairfax County, Prince William County, and the Shenandoah Valley trust our technicians to get their alignment right the first time. We provide a printed alignment report showing your vehicle's measurements before and after the adjustment.",whyUs:"Bingo Tire & Auto Service has been performing computerized wheel alignments across Northern Virginia since 2004. Our technicians understand that alignment is not a one-size-fits-all service — different vehicles, different tires, and different driving conditions require different approaches. We take the time to understand your driving habits and concerns before we adjust anything, and we'll provide a clear printout of your vehicle's measurements so you can see exactly what was corrected. We serve drivers from all over the NOVA region, including Springfield, Woodbridge, Alexandria, Centreville, and Winchester.",warnings:["Vehicle drifts or pulls to one side while driving straight","Steering wheel is off-center on a straight road","Tires show uneven or rapid wear on one edge","Vibration felt through the steering wheel","Squealing tires when turning","Vehicle recently hit a curb, pothole, or was in a minor collision"],included:["Four-wheel computerized alignment check","Toe, camber, and caster adjustment","Steering center adjustment","Tire pressure verification on all four tires","Printed alignment report before and after","Thrust angle correction (where applicable)"],faqs:[{question:"How often should I get an alignment?",answer:"We recommend checking alignment every 6,000 miles or once a year — and any time you hit a significant pothole, curb, or are in an accident. Installing new tires is also a great time for an alignment check to protect your new investment."},{question:"What's the difference between alignment and balancing?",answer:"Alignment adjusts the angle of your tires relative to each other and the road. Balancing corrects uneven weight distribution in the wheel and tire assembly. Both affect ride comfort and tire wear, and both should be checked regularly — especially after installing new tires."},{question:"Will an alignment fix my steering pull?",answer:"Often yes. A steering pull is a classic sign of misalignment. However, it can also be caused by unequal tire pressure or a worn suspension component. Our technicians will diagnose the root cause before making any adjustments."},{question:"My car is new — does it need an alignment?",answer:"New vehicles can come from the factory slightly out of alignment, and even small deviations will cause uneven tire wear over time. We recommend having your alignment checked within the first 10,000 miles, and annually after that."},{question:"Does alignment affect fuel economy?",answer:"Yes. Misaligned wheels create rolling resistance that forces your engine to work harder, reducing fuel efficiency. Correcting alignment can improve gas mileage noticeably — especially important for drivers commuting on Northern Virginia's busy highways every day."}]},{slug:"tune-up",name:"Tune-Up",category:"Auto Services",icon:l.A,image:"/images/services/tune-up.jpg",shortDescription:"Spark plug, air filter, and ignition system service.",seoTitle:"Engine Tune-Up in Springfield, Woodbridge & Northern Virginia, VA",fullDescription:"Professional engine tune-up service at all five Bingo Tire & Auto Service locations in Northern Virginia. We replace spark plugs, air filters, and service the ignition system to restore lost power, improve fuel economy, and reduce emissions. Drivers in Springfield, Woodbridge, Alexandria, Centreville, and Winchester trust Bingo Tire to keep their engines performing at their best.",bodyParagraphs:["Over time, spark plugs wear, air filters clog with dirt and debris, and ignition components degrade. The result is an engine that works harder to produce the same power — consuming more fuel, emitting more pollutants, and eventually producing rough idle and hesitation. A tune-up at Bingo Tire & Auto Service restores your engine's efficiency by replacing the components that have worn past their service life. Our technicians follow manufacturer specifications for every make and model, ensuring the correct spark plug type, gap, and torque for your specific engine.","Northern Virginia's stop-and-go traffic on I-66, I-95, Route 1, and Route 50 puts heavy demand on engines. Frequent acceleration and deceleration cycles in congested areas accelerate spark plug wear and air filter contamination. If it's been a while since your last tune-up or you're noticing reduced responsiveness when accelerating onto the highway, bring your vehicle to any Bingo Tire location for an evaluation. We'll tell you honestly what needs attention and what's still serviceable."],seoDescription:"Restore your engine's performance with a professional tune-up at Bingo Tire & Auto Service in Northern Virginia. We replace spark plugs, air filters, and service the ignition system on all makes and models.",cityContent:"Bingo Tire & Auto Service offers engine tune-up services at five Northern Virginia locations: Springfield, Woodbridge, Alexandria, Centreville, and Winchester. Whether you're in Fairfax County, Prince William County, or the Shenandoah Valley, one of our shops is nearby. Our technicians work on all makes and models — domestic and import, gas and diesel. Call your nearest location or walk in during business hours for a free inspection and tune-up recommendation.",whyUs:"Bingo Tire & Auto Service has been serving Northern Virginia drivers with honest, professional engine service since 2004. When it comes to tune-ups, we follow the manufacturer's maintenance schedule for your exact vehicle — we don't just replace parts for the sake of billing. If your spark plugs still have 20,000 miles of life in them, we'll tell you. If your air filter looks like it was pulled from a construction site, we'll show it to you and explain why it needs changing. Transparency is the foundation of everything we do at our five Northern Virginia locations.",warnings:["Difficulty starting the engine, especially when cold","Engine misfires, stumbles, or hesitates on acceleration","Noticeably worse fuel economy","Engine runs rough or idles unevenly","Failed Virginia emissions test","It's been more than 30,000 miles since your last tune-up"],included:["Spark plug inspection and replacement","Air filter inspection and replacement","Fuel filter inspection","Ignition wires and coils inspection","Throttle body cleaning","PCV valve check","Idle speed and timing check"],faqs:[{question:"How often does a car need a tune-up?",answer:"Older vehicles with conventional spark plugs typically need a tune-up every 30,000 miles. Modern vehicles with platinum or iridium plugs can go 60,000 to 100,000 miles. Check your owner's manual or bring your vehicle to any Bingo Tire location in Northern Virginia for a recommendation."},{question:"How much fuel economy improvement can I expect?",answer:"A properly tuned engine can improve fuel economy by 4% to 40% depending on how degraded the ignition components were. Replacing a severely clogged air filter alone can improve mileage by up to 10% — meaningful savings for Northern Virginia commuters."},{question:"Do I need a tune-up if my check engine light isn't on?",answer:"Yes. Many performance-affecting components degrade gradually without triggering a warning light. Worn spark plugs, a dirty air filter, and a weak ignition coil can all reduce performance and fuel economy significantly without ever illuminating a warning light."},{question:"What's the difference between a tune-up and engine diagnostics?",answer:"A tune-up is a scheduled maintenance service that replaces wear items like spark plugs and filters. Engine diagnostics is a diagnostic procedure performed in response to a warning light or specific symptom. They are complementary services — a tune-up may eliminate a check engine light caused by a misfiring spark plug, or diagnostics may reveal that you need a tune-up."},{question:"Can a tune-up help me pass the Virginia emissions test?",answer:"Yes, in many cases. A misfiring engine, rich fuel mixture, or malfunctioning ignition component can cause elevated emissions that fail the Virginia OBD test. A proper tune-up addressing the root cause can bring emissions back into compliance."}]},{slug:"state-inspection",name:"Virginia State Inspection",category:"Auto Services",icon:c.A,image:"/images/services/state-inspection.jpg",shortDescription:"Official Virginia safety and emissions inspection.",seoTitle:"Virginia State Inspection in Centreville & Springfield, VA | Bingo Tire & Auto Service",fullDescription:"Official Virginia state safety and emissions inspection at Bingo Tire & Auto Service in Centreville and Springfield, VA. Certified inspection stations with experienced, licensed inspectors. We thoroughly check your vehicle against all Virginia DMV safety and environmental standards, provide fast turnaround, and offer competitive repair pricing if your vehicle needs corrections to pass.",bodyParagraphs:["Every vehicle registered in Virginia must pass an annual state safety inspection. The inspection covers brakes, tires, steering, lights, horn, mirrors, wipers, and for applicable vehicles, an OBD emissions check. At Bingo Tire & Auto Service in Centreville (703-543-6900) and Springfield (703-440-0880), our Virginia-licensed inspectors perform thorough, efficient inspections and provide honest results. We are not in the business of failing vehicles unnecessarily — but we will flag every genuine safety concern that the Virginia inspection program requires us to address.","If your vehicle fails inspection, we'll provide a complete written report detailing every item that needs to be corrected. As a full-service auto repair shop, we can address many common inspection failures on the spot — worn brake pads, burned-out lights, cracked windshields, and tire tread depth are among the most frequent causes of failure. Virginia law gives you 15 days and 25 miles to make repairs and return for a free re-inspection, and our team will work efficiently to help you get compliant as quickly as possible."],seoDescription:"Get your Virginia state safety and emissions inspection at Bingo Tire & Auto Service. Certified inspectors, fast turnaround, and convenient locations in Springfield and Centreville, VA.",cityContent:"Bingo Tire & Auto Service performs Virginia State Inspections at two Northern Virginia locations: Centreville at 13600 Lee Hwy (703-543-6900) and Springfield at 7661 Fullerton Rd (703-440-0880). Both locations are certified Virginia inspection stations staffed by licensed inspectors. Drivers throughout Fairfax County and neighboring communities in Prince William County and Loudoun County frequently use our Centreville and Springfield locations for their annual inspection. Walk-ins are welcome — call ahead during busy seasons to confirm current wait times.",whyUs:"Bingo Tire & Auto Service has been a trusted Virginia State Inspection station in Centreville and Springfield since 2004. We're known throughout Northern Virginia for giving honest inspection results — we pass vehicles that pass and we explain clearly what needs to be fixed on vehicles that don't. As a full-service shop, we can often complete any necessary repairs on the same visit so you leave with a clean inspection sticker. Our pricing for inspection-related repairs is competitive and transparent, and we'll never inflate a repair to take advantage of your inspection deadline.",warnings:["Your current inspection sticker is expiring within 30 days","You just purchased a used vehicle in Virginia","You moved to Virginia and need to register your vehicle","Your vehicle registration renewal requires a passing inspection"],included:["Official Virginia safety inspection by a licensed inspector","Brake system check (pads, rotors, lines, parking brake)","Lighting and turn signal verification","Tire condition and tread depth check","Steering and suspension inspection","Horn, mirrors, and wipers check","Emissions OBD scan (applicable model years)"],faqs:[{question:"How much does a Virginia state inspection cost?",answer:"The official state-regulated fee is $16 for a standard passenger vehicle. This fee does not include any repairs that may be needed to pass. Bingo Tire charges the standard state fee — we do not add surcharges."},{question:"What happens if my vehicle fails the inspection?",answer:"If your vehicle fails, we'll provide a detailed written report of every item that needs correction. You'll have 15 days and up to 25 miles of driving to make the repairs and return for a free re-inspection. As a full-service shop, we can often complete the needed repairs on the same visit."},{question:"Do I need an appointment for a state inspection?",answer:"We accept walk-ins for state inspections at our Centreville and Springfield locations. Arriving early in the day reduces wait time. During busy periods — especially in spring and fall when many inspection stickers expire — we recommend calling ahead."},{question:"What does the Virginia state inspection check?",answer:"The inspection covers brakes, tires, steering, suspension, horn, mirrors, windshield and wipers, all exterior lights, fuel system, exhaust, and for applicable vehicles (1996 and newer), an OBD-II emissions scan to verify no active fault codes are affecting emissions controls."},{question:"Which Bingo Tire locations offer Virginia State Inspections?",answer:"Virginia State Inspections are currently available at our Centreville location (13600 Lee Hwy, 703-543-6900) and our Springfield location (7661 Fullerton Rd, 703-440-0880). Please call ahead to confirm current inspection availability and wait times."}],availableAt:["Centreville","Springfield"]},{slug:"steering-suspension",name:"Steering & Suspension",category:"Auto Services",icon:d.A,image:"/images/services/steering-suspension.jpg",shortDescription:"Shock absorbers, struts, tie rods, power steering.",seoTitle:"Steering & Suspension Repair in Springfield, Woodbridge & Northern Virginia, VA",fullDescription:"Expert steering and suspension repair at all five Bingo Tire & Auto Service locations in Northern Virginia. We repair and replace shocks, struts, tie rod ends, ball joints, control arm bushings, sway bar links, and power steering components on all makes and models. Drivers in Springfield, Woodbridge, Alexandria, Centreville, and Winchester trust Bingo Tire for safe, reliable suspension service.",bodyParagraphs:["Your vehicle's steering and suspension systems are responsible for keeping you in control on the road — especially on Northern Virginia's mix of smooth highways and rough city streets. Worn shocks and struts allow excessive body motion during cornering and braking, reducing your ability to control the vehicle in an emergency. Worn tie rod ends and ball joints introduce looseness into the steering that makes precise control difficult. At Bingo Tire & Auto Service, our technicians perform a thorough steering and suspension inspection to identify every worn or damaged component before it becomes a safety issue.","Suspension and steering repairs vary widely in complexity. Replacing a sway bar link is a simple, affordable job that can transform a clunking, uncomfortable ride. Replacing struts on a front-wheel drive vehicle requires compressing the spring — a job that must be done with professional equipment for safety reasons. Our technicians have the training, tools, and experience to handle every level of steering and suspension service from simple linkage replacements to full strut assembly replacements, always followed by a wheel alignment check to protect your tires."],seoDescription:"Worn shocks and steering components are a safety hazard. Bingo Tire & Auto Service in Northern Virginia repairs and replaces shocks, struts, tie rods, ball joints, and power steering systems on all makes and models.",cityContent:"Bingo Tire & Auto Service provides complete steering and suspension repair and replacement at five Northern Virginia locations: Springfield (703-440-0880), Woodbridge (703-494-8888), Alexandria (703-548-0333), Centreville (703-543-6900), and Winchester (540-667-7777). Whether you're dealing with a clunking noise over bumps on Route 28, a pulling vehicle on I-95, or a steering wheel that vibrates on the highway, our technicians can diagnose and fix the problem. Walk-ins are welcome.",whyUs:"Steering and suspension repairs require diagnostic skill and technical precision — and Bingo Tire & Auto Service has been delivering both in Northern Virginia since 2004. We never recommend steering or suspension repairs based on mileage alone. If a component still tests within specification, we'll tell you so. When a repair is needed, we use quality parts and back our work with a service guarantee. We always perform an alignment check after suspension work to ensure your tires wear evenly. Our customers in Springfield, Woodbridge, and Alexandria come back year after year because they trust us to be honest.",warnings:["Rough, bumpy, or excessively bouncy ride quality","Vehicle nose dives when braking","Body rolls excessively when cornering","Clunking, knocking, or squeaking sounds over bumps","Uneven or accelerated tire wear patterns","Steering feels loose, vague, or wanders at highway speed"],included:["Full steering and suspension inspection","Shock absorber and strut condition assessment","Ball joint and tie rod end inspection","Control arm bushing inspection","Sway bar and sway bar link check","Power steering fluid level and condition check","Post-repair wheel alignment check"],faqs:[{question:"How do I know if my shocks are worn out?",answer:"The bounce test is a simple check — press down firmly on each corner of the vehicle and release. Good shocks stop bouncing after one rebound. More than two rebounds indicates worn shocks. You may also notice excessive body roll, nose diving under braking, or a rough, unsettled ride on Northern Virginia's uneven roads."},{question:"How long do shocks and struts last?",answer:"Most shocks and struts last between 50,000 and 100,000 miles depending on road conditions. Northern Virginia's roads — with their combination of highway driving and pothole-filled surface streets — tend to wear suspension components faster than in smoother climates."},{question:"What's the difference between shocks and struts?",answer:"Struts are a structural component of the suspension system and support the vehicle's weight — they are integral to the suspension geometry. Shocks are separate damping components that control bounce and movement without affecting geometry. Your vehicle uses one type or the other depending on its design. We'll identify what you have and what needs attention."},{question:"Do I need an alignment after suspension repair?",answer:"In most cases, yes. Replacing struts, control arms, ball joints, or tie rod ends changes the suspension geometry, which directly affects alignment. We always recommend — and often include — an alignment check after suspension component replacement to protect your new parts and your tires."},{question:"Is a clunking noise from the front a suspension problem?",answer:"A clunking noise over bumps is a very common symptom of worn sway bar end links, worn ball joints, or loose strut mounts. It's not always expensive to fix — many times a worn sway bar link is the culprit, and it's a very affordable repair. Come in to any Bingo Tire location and we'll diagnose it accurately."}]},{slug:"batteries",name:"Batteries",category:"Auto Services",icon:h.A,image:"/images/services/batteries.jpg",shortDescription:"Battery test, replacement, and terminal cleaning.",seoTitle:"Car Battery Replacement in Springfield, Woodbridge & Northern Virginia, VA",fullDescription:"Professional battery testing, replacement, and charging system service at all five Bingo Tire & Auto Service locations in Northern Virginia. We carry all major battery brands and will ensure your vehicle starts reliably in every season — from Northern Virginia's cold winters to its hot, humid summers. Serving drivers in Springfield, Woodbridge, Alexandria, Centreville, and Winchester.",bodyParagraphs:["Car batteries don't always fail with dramatic warning signs. One day your car starts fine; the next morning it won't turn over at all. Cold Virginia winters are particularly hard on batteries — low temperatures reduce a battery's ability to deliver cold cranking amps (CCA), and a battery that seemed marginal in October may fail completely in January. At Bingo Tire & Auto Service, we use professional load testers to accurately measure your battery's current health and compare it to its rated CCA capacity. This gives you advance warning of a battery that's likely to fail before it actually leaves you stranded.","We stock batteries from trusted brands in a wide range of group sizes to fit vehicles from compact cars to full-size trucks and SUVs. Battery installation includes cleaning corrosion from the terminals, inspecting the battery cables and connections, and testing the alternator and charging system to confirm your new battery will be properly charged by the vehicle's electrical system. For vehicles that require battery registration or programming after replacement — many European and newer domestic models — our technicians handle that procedure as part of the installation."],seoDescription:"Don't get stranded with a dead battery. Bingo Tire & Auto Service offers free battery testing and fast battery replacement in Northern Virginia. We carry all major brands and will ensure your charging system is healthy too.",cityContent:"Bingo Tire & Auto Service provides free battery testing and fast battery replacement at all five Northern Virginia locations: Springfield (703-440-0880), Woodbridge (703-494-8888), Alexandria (703-548-0333), Centreville (703-543-6900), and Winchester (540-667-7777). Whether you're in Fairfax County, Prince William County, or the Shenandoah Valley, we're close by. Battery tests take just a few minutes and require no appointment — walk in any time during business hours and we'll test your battery for free.",whyUs:"Bingo Tire & Auto Service has helped thousands of Northern Virginia drivers avoid the frustration of a dead battery since 2004. We offer free battery tests at all five locations because we believe preventive service is better than emergency service. If your battery tests marginal, we'll show you the results and explain what they mean. If it tests fine, we'll tell you that too — we're not going to sell you a battery you don't need. Our technicians always test the full charging system alongside the battery to make sure a failing alternator isn't what's killing your battery.",warnings:["Vehicle is slow to start or cranks weakly","Battery warning light is illuminated","Battery is more than 3 to 4 years old","Lights and electronics dim when the engine is running","Corroded, swollen, or leaking battery terminals","Vehicle requires jump-starts more than once"],included:["Complete professional battery load test","Alternator output and charging system check","Starter draw test","Terminal cleaning and corrosion removal","Battery installation (all major brands in stock)","Battery programming/registration (applicable vehicles)"],faqs:[{question:"How long does a car battery last?",answer:"Most car batteries last 3 to 5 years. Northern Virginia's temperature extremes — cold winters and hot summers — accelerate battery wear. If your battery is approaching 4 years old, have it load-tested at any Bingo Tire location even if it seems to be working fine."},{question:"Can you test my battery for free?",answer:"Yes — we offer free battery testing at all five Northern Virginia locations. The test takes just a few minutes and accurately measures your battery's current health, cold cranking amp capacity, and state of charge."},{question:"Will my radio and settings reset after a battery change?",answer:"Many modern vehicles lose radio presets, power window calibration, and other settings after a battery replacement. Some European and newer domestic vehicles also require a battery registration procedure to ensure the charging system manages the new battery correctly. We handle all of these steps as part of our battery installation service."},{question:"My battery is fine but my car still won't start — what's wrong?",answer:"A no-start condition with a healthy battery could indicate a failing starter motor, a bad ignition switch, a security system issue, or a problem with the fuel or ignition system. Bring your vehicle to any Bingo Tire location and we'll diagnose the root cause."},{question:"Does extreme heat affect car batteries?",answer:"Yes — heat is actually more damaging to batteries than cold. High temperatures accelerate the chemical reactions inside a battery that cause it to degrade. A battery that is borderline healthy may survive through winter and then fail during a Virginia summer heat wave. Annual testing is the best preventive measure."}]},{slug:"150-point-check",name:"150 Point Check",category:"Auto Services",icon:u.A,image:"/images/services/150-point-check.jpg",shortDescription:"Comprehensive vehicle inspection of major systems.",seoTitle:"150-Point Vehicle Inspection in Springfield, Woodbridge & Northern Virginia, VA",fullDescription:"Bingo Tire & Auto Service's comprehensive 150-point vehicle inspection covers every major system on your car, truck, or SUV. Available at all five Northern Virginia locations — Springfield, Woodbridge, Alexandria, Centreville, and Winchester — this detailed inspection is ideal before buying a used car, preparing for a road trip, or simply staying ahead of costly repairs.",bodyParagraphs:["A standard oil change includes a quick visual scan of obvious items. Our 150-point inspection is an entirely different level of service. Our technicians systematically inspect every major vehicle system — engine, transmission, drivetrain, brakes, steering, suspension, tires, battery, charging system, cooling system, fuel system, exhaust, and all lighting and electrical components. Each item is assessed and categorized: items that are fine, items that should be monitored, and items that need immediate attention. You receive a clear, written report with priority rankings when the inspection is complete.","This service is particularly valuable for drivers who have purchased a used vehicle, drivers with high-mileage vehicles approaching major service intervals, and anyone planning a long road trip across Virginia or beyond. Northern Virginia drivers who commute significant distances on I-66, I-95, or Route 7 benefit enormously from knowing their vehicle's true condition before a problem develops on the road. The 150-point inspection gives you complete visibility into your vehicle's health — not a sales pitch, but a comprehensive, honest assessment."],seoDescription:"Know exactly what's going on with your vehicle before a road trip or used car purchase. Bingo Tire's 150-point vehicle inspection covers every major system and gives you a detailed report. Available at all 5 Northern Virginia locations.",cityContent:"Bingo Tire & Auto Service performs the 150-point vehicle inspection at all five Northern Virginia locations: Springfield at 7661 Fullerton Rd (703-440-0880), Woodbridge at 1330 Old Bridge Rd (703-494-8888), Alexandria at 2920 Richmond Hwy (703-548-0333), Centreville at 13600 Lee Hwy (703-543-6900), and Winchester at 709 N Loudoun St (540-667-7777). Whether you're in Fairfax County, Prince William County, Loudoun County, or Frederick County, we're close by. Call ahead to schedule your inspection for the fastest service.",whyUs:"At Bingo Tire & Auto Service, we've been performing comprehensive vehicle inspections in Northern Virginia since 2004. Our 150-point inspection is not a marketing tool designed to generate repair sales — it's a genuine diagnostic service performed by technicians who care about your safety. We'll tell you the truth about your vehicle's condition, prioritize what needs attention now versus what can wait, and give you the information you need to make smart maintenance decisions. If nothing is wrong, we'll tell you that too.",warnings:["Buying a used vehicle and want an independent inspection","Preparing for a long road trip","Vehicle has high mileage (over 75,000 miles)","You haven't had a full inspection in over a year","Multiple warning lights are illuminated simultaneously","Vehicle recently came out of extended storage"],included:["Engine and drivetrain visual and functional inspection","Complete brake system assessment","Steering and suspension component inspection","Tire condition, tread depth, and sidewall check","Battery and full charging system test","All fluid levels and condition checks","Lighting and electrical systems check","Exhaust system visual inspection","Detailed written report with priority rankings"],faqs:[{question:"How is a 150-point check different from a regular oil change inspection?",answer:"The 150-point check is a comprehensive, dedicated inspection covering every major system in detail with a written priority report. An oil change inspection is a quick visual check — it is not a substitute for a thorough inspection. The two services serve very different purposes."},{question:"Should I get this before buying a used car?",answer:"Absolutely. A pre-purchase inspection is one of the smartest investments you can make. Our technicians regularly spot undisclosed issues — frame damage, worn suspension components, engine leaks, brake problems — that can save buyers thousands in unexpected repairs. Bring the vehicle to any Bingo Tire location in Northern Virginia."},{question:"How long does the inspection take?",answer:"The 150-point inspection typically takes 60 to 90 minutes. We'll call or text you when it's complete and walk you through the written report, explaining each item and its priority level."},{question:"Will the inspection tell me how much it will cost to fix everything?",answer:"Yes. For any item we flag as needing attention, we'll provide a written estimate for the repair. There is never any pressure to have the work done immediately — the inspection is about information. You decide what to address and when."},{question:"Can I get a 150-point inspection on any vehicle?",answer:"Yes — we perform the 150-point inspection on all makes and models, domestic and import, gas and diesel, cars, trucks, SUVs, and minivans. Any vehicle that can be driven or towed to one of our Northern Virginia locations can be inspected."}]},{slug:"flat-tire-repair",name:"Flat Tire Repair",category:"Tire and Wheel",icon:g.A,image:"/images/services/flat-tire-repair.jpg",shortDescription:"Puncture repair, plug and patch, valve stem.",seoTitle:"Flat Tire Repair in Springfield, Woodbridge & Northern Virginia, VA",fullDescription:"Fast, affordable flat tire repair at all five Bingo Tire & Auto Service locations across Northern Virginia. We use the industry-standard plug and patch repair method to safely fix punctures and get you back on the road quickly. Drivers throughout Springfield, Woodbridge, Alexandria, Centreville, and Winchester trust Bingo Tire for professional flat tire service.",bodyParagraphs:["Getting a flat tire on Northern Virginia's roads is a frustrating experience — especially during rush hour on I-95, I-395, or the Beltway. Nails and screws picked up from construction zones are the most common cause of flat tires in our area, and in most cases a professionally repaired tire is just as safe as a new one. At Bingo Tire & Auto Service, we follow the industry-standard repair procedure: remove the tire from the wheel, inspect the interior for damage, drill out the puncture cleanly, install a combination plug-and-patch unit from the inside, and remount and balance the tire. This is a permanent repair — not a temporary fix.","Not every flat can be repaired, and we'll be honest with you about it. Punctures in the sidewall or shoulder, tires that have been driven on while flat, and tires with structural damage require replacement. We won't try to repair a tire that can't be safely repaired — because your safety on the road is more important than a short-term fix. If a replacement is needed, we carry an extensive inventory of new and used tires at all five Northern Virginia locations, in a wide range of sizes and price points."],seoDescription:"Got a flat tire in Northern Virginia? Bingo Tire & Auto Service provides fast, affordable flat tire repair at all 5 locations. We use the industry-standard plug and patch method and can have you back on the road quickly.",cityContent:"Bingo Tire & Auto Service provides flat tire repair and replacement at five Northern Virginia locations: Springfield (703-440-0880), Woodbridge (703-494-8888), Alexandria (703-548-0333), Centreville (703-543-6900), and Winchester (540-667-7777). If you have a flat near any of our locations, come directly to us — no appointment needed. Our Alexandria location is open until midnight, and our Woodbridge location is open until 10 PM, making us the accessible choice even after a late commute or an evening errand.",whyUs:"Bingo Tire & Auto Service has been fixing flat tires for Northern Virginia drivers since 2004. We're known throughout Fairfax County, Prince William County, and the Shenandoah Valley for fast, professional service at fair prices. We'll inspect your tire thoroughly, tell you honestly whether it can be repaired or needs to be replaced, and get you back on the road as quickly as possible. We never overcharge for a flat repair, and we never recommend tire replacement when a repair will do the job safely.",warnings:["TPMS warning light has come on","Vehicle pulling to one side while driving","Flapping, thumping, or thumping sound while driving","Visible nail, screw, or object embedded in the tire","Tire appears visibly flat or very low to the ground","Unusual vibration at highway speeds"],included:["Removal of tire from wheel","Full interior inspection to locate and assess the puncture","Industry-standard plug and patch repair from the inside","Valve stem inspection and replacement if needed","Proper inflation to manufacturer specifications","Remount and torque to specification","TPMS sensor reset"],faqs:[{question:"Can all flat tires be repaired?",answer:"Not always. A tire can be safely repaired if the puncture is in the tread area and smaller than 1/4 inch in diameter. Sidewall damage, shoulder punctures, and any tire driven on while flat cannot be safely repaired and will require replacement."},{question:"Is a plug repair as safe as a patch?",answer:"A plug alone is considered a temporary fix. The permanent, industry-standard repair uses a combination plug-and-patch unit applied from the inside of the tire. This is the method we use at all five Bingo Tire locations — it is safe for the remaining life of the tire."},{question:"What should I do if I get a flat on the road in Northern Virginia?",answer:"Pull off the road safely, activate your hazard lights, and avoid driving on the flat rim. Install your spare tire if you have one, or call for roadside assistance. Once you have a spare on, drive to the nearest Bingo Tire location. Driving on a flat damages the tire's internal structure and often makes it irreparable."},{question:"How much does a flat tire repair cost?",answer:"Flat tire repair is one of the most affordable services we offer. Call any of our five Northern Virginia locations for current pricing. In most cases the repair is completed in 30 minutes or less with no appointment required."},{question:"Do I need to replace all four tires if one goes flat?",answer:"Not usually. If the damaged tire can be repaired, you simply have it repaired and continue using all four tires. If it needs to be replaced, we recommend matching the new tire to the remaining tires in terms of brand, model, and tread depth — especially on all-wheel drive vehicles, where significant tread depth differences can stress the drivetrain."}]},{slug:"tpms",name:"TPMS Service",category:"Tire and Wheel",icon:p.A,image:"/images/services/tpms.jpg",shortDescription:"Sensor diagnosis, reset, and replacement.",seoTitle:"TPMS Sensor Service & Reset in Springfield, Woodbridge & Northern Virginia, VA",fullDescription:"Professional TPMS (Tire Pressure Monitoring System) diagnosis, reset, and sensor replacement at all five Bingo Tire & Auto Service locations in Northern Virginia. Don't ignore your tire pressure warning light — proper tire pressure is critical for safety, fuel efficiency, and tire longevity. We service TPMS systems on all makes and models in Springfield, Woodbridge, Alexandria, Centreville, and Winchester.",bodyParagraphs:["The TPMS warning light on your dashboard is required by federal law on all vehicles manufactured since 2008 — it's there to alert you when one or more tires drop below a safe pressure threshold. But the TPMS system itself requires maintenance that many drivers overlook. Sensors use an internal battery that typically lasts 5 to 10 years. When a sensor battery dies, the TPMS light comes on and stays on — even if all your tires are perfectly inflated. At Bingo Tire & Auto Service, we use specialized TPMS scan tools to identify exactly which sensor has failed and whether the issue is the sensor, the battery, the valve stem, or the system's programming.","A common cause of TPMS issues in Northern Virginia is the seasonal temperature swing. As temperatures drop in fall and winter, tire pressure decreases — roughly 1 PSI for every 10\xb0F drop in temperature. This can push borderline tires below the sensor threshold, triggering the warning light even on tires that were properly inflated in warmer weather. Adding 2 to 3 PSI in the fall is good preventive practice. If your light comes on and all four tires are at the correct pressure, a failed sensor is likely the cause."],seoDescription:"TPMS light on in your car? Bingo Tire & Auto Service in Northern Virginia diagnoses, resets, and replaces TPMS sensors on all makes and models. Don't ignore your tire pressure warning light — it's there to keep you safe.",cityContent:"Bingo Tire & Auto Service provides TPMS diagnosis, reset, and sensor replacement at five Northern Virginia locations: Springfield (703-440-0880), Woodbridge (703-494-8888), Alexandria (703-548-0333), Centreville (703-543-6900), and Winchester (540-667-7777). If your TPMS light is on and you're unsure why, bring your vehicle to any of our locations for a quick diagnostic scan. Most TPMS issues can be diagnosed in minutes, and many can be resolved the same day.",whyUs:"TPMS service requires specialized scan tools and technical knowledge that not all shops have. At Bingo Tire & Auto Service, we've invested in professional TPMS equipment that can service virtually every make and model sold in Northern Virginia. We'll diagnose the root cause accurately — whether it's low pressure, a failed sensor, a programming issue, or a valve stem problem — and fix it correctly the first time. With five convenient locations across Springfield, Woodbridge, Alexandria, Centreville, and Winchester, we're always close by when that warning light comes on.",warnings:["TPMS warning light is on (steady or flashing)","TPMS light came on after getting new tires installed","Tire pressure gauge shows correct pressure but light remains on","Cold weather causing the warning light to appear","One or more sensors are not reading on your dashboard display"],included:["TPMS system scan and fault code retrieval","Sensor identification and location","Sensor battery life assessment","TPMS sensor replacement (OEM or quality aftermarket)","System relearn and reinitialization procedure","Tire pressure verification and correction on all four wheels"],faqs:[{question:"Why is my TPMS light on even though my tires look fine?",answer:"Tires can look fine but be 5 to 10 PSI below recommended pressure. Cold Virginia winters can also trigger the light as temperatures drop. And sometimes the sensor itself has failed — requiring replacement rather than just air."},{question:"Do TPMS sensors need to be replaced when I get new tires?",answer:"Not automatically, but TPMS sensor service kits — the valve core, cap, seal, and nut — should be replaced at every tire change to prevent corrosion and leaks. The full sensor typically lasts 5 to 10 years until the internal battery dies."},{question:"Can I drive with the TPMS light on?",answer:"Yes, but check your tire pressure with a manual gauge first. If any tire is underinflated, add air immediately. Driving on underinflated tires generates excessive heat, accelerates wear, and can cause a blowout — especially at highway speeds on I-66 or I-95."},{question:"Why does my TPMS light come on every winter?",answer:"Tire pressure drops approximately 1 PSI for every 10\xb0F temperature decrease. Northern Virginia winters commonly see drops of 20 to 40 degrees, which can lower tire pressure by 2 to 4 PSI — enough to trigger the TPMS warning. Adding a couple PSI in the fall can prevent this. If the light still comes on after inflating to the correct pressure, a sensor issue is likely."},{question:"How long does TPMS sensor replacement take?",answer:"A single sensor replacement typically takes 30 to 60 minutes including the sensor swap and system relearn procedure. Replacing all four sensors at the same time takes 1 to 2 hours and is often more economical than replacing them one at a time as they fail."}]},{slug:"tire-rotation",name:"Tire Rotation",category:"Tire and Wheel",icon:m.A,image:"/images/services/tire-rotation.jpg",shortDescription:"Regular rotation to ensure even tire wear.",seoTitle:"Tire Rotation Service in Springfield, Woodbridge & Northern Virginia, VA",fullDescription:"Professional tire rotation service at all five Bingo Tire & Auto Service locations in Northern Virginia. Regular rotation is one of the most cost-effective ways to maximize tire life and maintain even tread wear. We rotate tires on all makes and models in Springfield, Woodbridge, Alexandria, Centreville, and Winchester — with the correct manufacturer-specified rotation pattern every time.",bodyParagraphs:["Front tires and rear tires wear at very different rates depending on your vehicle's drivetrain configuration. On a front-wheel drive vehicle — the most common type in Northern Virginia — front tires handle steering, acceleration, and braking simultaneously, causing them to wear two to three times faster than rear tires. Without regular rotation, you'll end up replacing front tires long before the rears are worn out, wasting money and missing the opportunity to replace all four tires as a set. Regular rotation equalizes wear across all four tires, letting each position wear more slowly and evenly.","Tire rotation is also a valuable inspection opportunity. Every time we remove your wheels to rotate them, we perform a visual brake inspection and measure tread depth on all four tires. This gives us — and you — a clear picture of how your tires are wearing. Abnormal wear patterns (cupping, one-sided wear, center wear) can indicate alignment problems, inflation issues, or worn suspension components that need attention before they damage your new tires. We'll let you know what we see every time."],seoDescription:"Regular tire rotation is one of the most cost-effective ways to extend tire life. Bingo Tire & Auto Service in Northern Virginia rotates tires on all vehicles using the correct rotation pattern. Walk-ins welcome.",cityContent:"Bingo Tire & Auto Service provides professional tire rotation service at five Northern Virginia locations: Springfield (703-440-0880), Woodbridge (703-494-8888), Alexandria (703-548-0333), Centreville (703-543-6900), and Winchester (540-667-7777). Tire rotation takes about 30 minutes with no appointment required. We often pair tire rotation with an oil change to make the most of your time. Walk-ins are welcome at all five locations throughout Fairfax County, Prince William County, and the Shenandoah Valley.",whyUs:"Bingo Tire & Auto Service has been rotating tires for Northern Virginia drivers since 2004. We follow the manufacturer-specified rotation pattern for every vehicle — not a generic cross-pattern that may not be appropriate for your tires or drivetrain. Our technicians torque all lug nuts to factory specification using a calibrated torque wrench, never an uncalibrated impact gun. We check and adjust tire pressure to the door placard spec on all four tires with every rotation. These details matter, and they're why our customers in Springfield, Woodbridge, Alexandria, Centreville, and Winchester keep coming back.",warnings:["You've driven 5,000 to 7,500 miles since your last rotation","Front tires are wearing noticeably faster than rear tires","One side of a tire is wearing faster than the other","You notice vibration at highway speeds","It has been more than 6 months since your last rotation"],included:["Removal and rotation of all four wheels","Manufacturer-specified rotation pattern applied","All lug nuts torqued to factory specification","Tire pressure check and adjustment on all four tires","Visual brake inspection during rotation","Tread depth measurement on all tires"],faqs:[{question:"How often should I rotate my tires?",answer:"Most manufacturers recommend tire rotation every 5,000 to 7,500 miles, or at every oil change. Many tire warranties require regular rotation to remain valid — check your tire documentation or ask us."},{question:"Does tire rotation really make a difference?",answer:"Significantly. On a front-wheel drive vehicle, rotating tires every 6,000 miles can effectively double or triple the life of your front tires by allowing all four tires to wear evenly. Given tire prices, regular rotation is one of the highest-ROI maintenance services available."},{question:"Does tire rotation matter on all-wheel drive vehicles?",answer:"It's especially critical on AWD vehicles. Significant differences in tread depth between tires can force the differentials to compensate continuously, leading to premature and expensive drivetrain wear. Regular rotation is mandatory for AWD vehicle owners in Northern Virginia."},{question:"What rotation pattern should be used?",answer:"The correct pattern depends on whether your vehicle is FWD, RWD, or AWD, and whether your tires are directional (unidirectional) or non-directional. Directional tires can only be moved front-to-rear on the same side; non-directional tires can be cross-rotated. We always use the correct pattern for your specific setup."},{question:"Can I get a tire rotation with my oil change?",answer:"Yes — and we encourage combining services whenever possible to save time. An oil change plus tire rotation takes about 45 to 60 minutes at any Bingo Tire location in Northern Virginia. It's the most efficient way to stay on top of two of the most important regular maintenance services."}]},{slug:"tire-balancing",name:"Tire Balancing",category:"Tire and Wheel",icon:y.A,image:"/images/services/tire-balancing.jpg",shortDescription:"Computerized wheel balancing to eliminate vibration.",seoTitle:"Tire Balancing in Springfield, Woodbridge & Northern Virginia, VA",fullDescription:"Professional computerized tire balancing at all five Bingo Tire & Auto Service locations in Northern Virginia. We use dynamic balancing equipment to eliminate steering wheel vibration, reduce tire wear, and protect your suspension from the stress of imbalanced wheels. Serving drivers in Springfield, Woodbridge, Alexandria, Centreville, and Winchester.",bodyParagraphs:["Even a small weight imbalance in a wheel and tire assembly creates significant vibration at highway speed. A wheel that is just 1/4 ounce out of balance produces a force equivalent to hitting a small bump every tire revolution. At 60 mph, that's hundreds of impacts per minute transmitted through your steering wheel, suspension, and wheel bearings. Over time, this vibration accelerates wear on your tires, wheel bearings, and steering components. At Bingo Tire & Auto Service, our computerized dynamic balancers spin your wheel and tire assembly at road speed and measure imbalance to the precision needed to place weights correctly.","Tire balancing is most commonly needed when new tires are installed, but it's also required after any significant impact — hitting a pothole on I-66 or a curb in Springfield can knock wheel weights off a rim and instantly create an imbalance. If you notice steering wheel vibration that wasn't there before, or if the vibration appears at a specific speed and then smooths out at higher speeds, imbalanced wheels are the most likely cause. We balance all wheel and tire combinations — from small economy cars to large SUVs and trucks."],seoDescription:"Tire vibration and uneven wear are signs your wheels need balancing. Bingo Tire & Auto Service uses computerized wheel balancing equipment to eliminate vibration and extend tire life at all 5 Northern Virginia locations.",cityContent:"Bingo Tire & Auto Service provides computerized tire balancing at five Northern Virginia locations: Springfield (703-440-0880), Woodbridge (703-494-8888), Alexandria (703-548-0333), Centreville (703-543-6900), and Winchester (540-667-7777). If you're experiencing steering wheel vibration while driving on Northern Virginia's highways, bring your vehicle to any of our locations — no appointment needed. Most balancing services are completed within 30 to 45 minutes.",whyUs:"At Bingo Tire & Auto Service, we've been balancing wheels the right way in Northern Virginia since 2004. We don't rush the balancing process or make shortcuts. Our technicians remove old wheel weights before installing new ones, spin the assembly at the proper speed, and verify balance accuracy before returning the wheel to your vehicle. We use quality stick-on and clip weights appropriate for your specific wheels, including low-profile alloy wheels where improper weight placement can cause cosmetic damage. If you're experiencing vibration, we'll find the cause and fix it right.",warnings:["Vibration felt in the steering wheel at highway speeds (55 mph and above)","Vibration felt through the seat or floor at specific speeds","Cupping or scalloping wear pattern visible on tire tread","New tires were recently installed","You hit a significant pothole or curb","Steering wheel shakes noticeably when braking at speed"],included:["Computerized dynamic balance of all four tires","Removal of all old wheel weights","Precision placement of new balance weights","Road force variation measurement (where applicable)","Visual inspection of tires for damage and abnormal wear","Valve stem condition check"],faqs:[{question:"What's the difference between balancing and alignment?",answer:"Balancing corrects uneven weight distribution in the wheel and tire assembly to eliminate vibration. Alignment corrects the angles of your wheels relative to each other and the road to prevent steering pull and uneven tire wear. Both are important maintenance services — balancing typically causes vibration, alignment typically causes pulling and uneven wear."},{question:"How often do tires need to be balanced?",answer:"Tires should be balanced every 6,000 to 12,000 miles, or whenever you notice vibration. Balancing should always be performed when new tires are installed, and after any impact that could have displaced a wheel weight — like hitting a pothole on I-95 or a curb in Alexandria."},{question:"Can unbalanced tires damage my car?",answer:"Yes. The repetitive vibration from imbalanced wheels accelerates wear on wheel bearings, tie rod ends, ball joints, and other steering and suspension components. Addressing vibration promptly is much less expensive than replacing worn suspension parts."},{question:"Why does my steering wheel only vibrate at certain speeds?",answer:"Wheel imbalance causes vibration that is frequency-dependent — it is most noticeable at specific speeds where the vibration frequency coincides with a natural resonance frequency of the vehicle's steering and suspension system. As speed increases past that point, the vibration often smooths out. This speed-specific pattern is a strong diagnostic indicator of wheel imbalance."},{question:"Is tire balancing included when I buy new tires at Bingo Tire?",answer:"Yes. All new tire installations at Bingo Tire & Auto Service include computerized balancing as part of the mounting service. We also include a TPMS reset and torque of lug nuts to factory specification. You leave with a complete, ready-to-drive installation."}]}],v=[{id:"springfield",name:"Springfield",address:"7661 Fullerton Rd",city:"Springfield",state:"VA",zip:"22153",phone:"(703) 440-0880",rating:4.3,reviewCount:"54+",mapImage:"/images/springfield.jpg",mapUrl:"https://maps.google.com/?q=7661+Fullerton+Rd,+Springfield,+VA+22153",hours:[{day:"Monday",hours:"9:00 AM – 6:00 PM"},{day:"Tuesday",hours:"9:00 AM – 6:00 PM"},{day:"Wednesday",hours:"9:00 AM – 6:00 PM"},{day:"Thursday",hours:"9:00 AM – 6:00 PM"},{day:"Friday",hours:"9:00 AM – 6:00 PM"},{day:"Saturday",hours:"9:00 AM – 4:00 PM"},{day:"Sunday",hours:"9:00 AM – 4:00 PM"}],attributes:["Free Wi-Fi","Accepts Credit Cards","BBB A+ Rated"],reviews:[{author:"Kofi M.",rating:5,text:"Great service. Very pleasant and professional staff. Manager took care of me. Will definitely be back.",source:"Yelp"},{author:"MechanicAdvisor",rating:5,text:"I went to 2 places and they both told me I needed new tires, 2 new rims, brake pads and rotors. The guy at Bingo Tires told me I just needed 2 tires and to rotate my tires. Honest shop.",source:"MechanicAdvisor"},{author:"Mattheus T.",rating:5,text:"I had a tire that was damaged and needed to be replaced. They removed my old tire and mounted my new tire quickly and professionally.",source:"Yelp"}],highlights:["In business since 2004","Quick no-appointment service","Honest assessments"]},{id:"woodbridge",name:"Woodbridge",address:"1330 Old Bridge Rd",city:"Woodbridge",state:"VA",zip:"22192",phone:"(703) 494-8888",rating:4.5,reviewCount:"37+",mapImage:"/images/woodbridge.jpg",mapUrl:"https://maps.google.com/?q=1330+Old+Bridge+Rd,+Woodbridge,+VA+22192",hours:[{day:"Monday",hours:"8:00 AM – 10:00 PM"},{day:"Tuesday",hours:"8:00 AM – 10:00 PM"},{day:"Wednesday",hours:"8:00 AM – 10:00 PM"},{day:"Thursday",hours:"8:00 AM – 10:00 PM"},{day:"Friday",hours:"8:00 AM – 10:00 PM"},{day:"Saturday",hours:"8:00 AM – 10:00 PM"},{day:"Sunday",hours:"9:00 AM – 7:00 PM"}],attributes:["Open Late Until 10 PM","Military Discount","Free Wi-Fi","Accepts Credit Cards","Curbside Pickup"],reviews:[{author:"Verified Customer",rating:5,text:"I came in with a punctured tire that was leaking air. I was there for about 20 minutes and left with a fixed tire for very cheap. Will be returning for all my tire needs.",source:"Yelp"},{author:"Spanish-speaking Customer",rating:5,text:"Excelente Servicio. The staff was very friendly and it was the only place open after 8 PM. Highly recommend!",source:"Yelp"},{author:"Verified Customer",rating:5,text:"Mudasir and the team are fantastic. Fast, knowledgeable, and great pricing. They handled our tires perfectly.",source:"Yelp"}],highlights:["Open until 10 PM Mon–Sat","700+ inspected used tires in stock","Military discount available"]},{id:"alexandria",name:"Alexandria",address:"2920 Richmond Hwy",city:"Alexandria",state:"VA",zip:"22305",phone:"(703) 548-0333",rating:4.5,reviewCount:"130+",mapImage:"/images/alexandria.jpg",mapUrl:"https://maps.google.com/?q=2920+Richmond+Hwy,+Alexandria,+VA+22305",hours:[{day:"Monday",hours:"8:00 AM – 12:00 AM"},{day:"Tuesday",hours:"8:00 AM – 12:00 AM"},{day:"Wednesday",hours:"8:00 AM – 12:00 AM"},{day:"Thursday",hours:"8:00 AM – 12:00 AM"},{day:"Friday",hours:"8:00 AM – 12:00 AM"},{day:"Saturday",hours:"8:00 AM – 12:00 AM"},{day:"Sunday",hours:"8:00 AM – 12:00 AM"}],attributes:["Open Until Midnight 7 Days","3,000+ Used Tires In Stock","Accepts Credit Cards"],reviews:[{author:"Business Owner",rating:5,text:"I can't say enough good things about Alphonso Carrington and the amazing team at Bingo Tires. They've been a tremendous help to me and my small business.",source:"Google"},{author:"Verified Customer",rating:5,text:"Great shop! Excellent prices. Hard to find a good tire place that doesn't try to milk you for money. These guys are friendly, quick and do good work.",source:"Google"},{author:"Verified Customer",rating:5,text:"The very best car care place in the area. I bring my car here for tire changes, oil changes, and all maintenance.",source:"Google"}],highlights:["Open until midnight every day","3,000+ used tires in stock","130+ Google reviews"]},{id:"centreville",name:"Centreville",address:"13600 Lee Hwy",city:"Centreville",state:"VA",zip:"20120",phone:"(703) 543-6900",rating:3.9,reviewCount:"15+",mapImage:null,mapUrl:"https://maps.google.com/?q=13600+Lee+Hwy,+Centreville,+VA+20120",hours:[{day:"Monday",hours:"8:00 AM – 6:00 PM"},{day:"Tuesday",hours:"9:00 AM – 6:00 PM"},{day:"Wednesday",hours:"8:00 AM – 6:00 PM"},{day:"Thursday",hours:"8:00 AM – 6:00 PM"},{day:"Friday",hours:"8:00 AM – 6:00 PM"},{day:"Saturday",hours:"9:00 AM – 4:00 PM"},{day:"Sunday",hours:"Closed"}],attributes:["Women-Owned","Asian-Owned","LGBTQ+ Friendly","30-Day Warranty on Used Tires","Accepts Credit Cards"],reviews:[{author:"Verified Customer",rating:5,text:"Best car care place around the area. Always take my car here for tire changes, oil changes, and general maintenance.",source:"Yelp"},{author:"Verified Customer",rating:4,text:"Good full-service shop. They handle tires, brakes, oil changes, and more. Staff is knowledgeable and professional.",source:"Yelp"}],highlights:["Women-owned & Asian-owned","30-day warranty on used tires","Full-service auto repair"]},{id:"winchester",name:"Winchester",address:"709 N Loudoun St",city:"Winchester",state:"VA",zip:"22601",phone:"(540) 667-7777",rating:4.2,reviewCount:"20+",mapImage:"/images/winchester.jpg",mapUrl:"https://maps.google.com/?q=709+N+Loudoun+St,+Winchester,+VA+22601",hours:[{day:"Monday",hours:"8:00 AM – 6:00 PM"},{day:"Tuesday",hours:"8:00 AM – 6:00 PM"},{day:"Wednesday",hours:"8:00 AM – 6:00 PM"},{day:"Thursday",hours:"8:00 AM – 6:00 PM"},{day:"Friday",hours:"8:00 AM – 6:00 PM"},{day:"Saturday",hours:"8:00 AM – 4:00 PM"},{day:"Sunday",hours:"Closed"}],attributes:["Accepts Credit Cards","Serving the Shenandoah Valley"],reviews:[{author:"Verified Customer",rating:5,text:"Reliable and honest shop. They've been serving Winchester for years and I trust them completely with my vehicle.",source:"Google"}],highlights:["Serving Winchester since 2004","New & used tires","Full auto repair"]}],w=[{id:"oil-change",title:"Oil Change",price:"$69.99",originalPrice:"$89.99",description:"Full-service oil change with filter replacement and a multi-point inspection. All oil types available — conventional, synthetic blend, and full synthetic."},{id:"rotation-oil-change",title:"Tire Rotation & Oil Change",price:"$110",originalPrice:"$139.99",description:"Get your oil changed and tires rotated in one visit. Includes filter replacement and multi-point inspection. A great way to maintain your vehicle and extend tire life."},{id:"brake-pad",title:"Brake Pad Replacement",price:"$79.99",originalPrice:"$129.99",description:"Per axle. Includes new brake pads and a full brake system inspection. We use quality pads that meet or exceed OEM specs. Call to confirm fitment for your vehicle."},{id:"brake-rotor",title:"Brake Rotor Replacement",price:"$139.99",description:"Per axle. Includes new rotors and brake pads installed and inspected by our certified technicians. Pricing may vary by vehicle — call your location for a quote."},{id:"alignment-package",title:"Tire Alignment + Mounting & Balance (4 Tires)",price:"$199.99",originalPrice:"$249.99",description:"Complete package: computer wheel alignment plus mounting and balancing of four tires. Ideal when purchasing new tires. Proper alignment protects your investment and improves handling."},{id:"alignment-check",title:"Wheel Alignment Check",price:"Free",description:"Not sure if your alignment is off? Stop by for a complimentary wheel alignment check. We'll let you know if your vehicle is out of spec — no obligation."},{id:"state-inspection",title:"VA State Inspection",price:"$16.00",description:"Official Virginia state safety inspection at our Centreville (13600 Lee Hwy) and Springfield (7661 Fullerton Rd) locations. Walk-ins welcome — call ahead during busy periods."}]},7653:(e,i,n)=>{n.d(i,{cn:()=>a});var t=n(4650),r=n(8585);function a(){for(var e=arguments.length,i=Array(e),n=0;n<e;n++)i[n]=arguments[n];return(0,r.QP)((0,t.$)(i))}}}]);